using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "https://localhost:8081",
            "C2y6yDjf5/R+ob0N8A7Cgv30VRDJIWEHLM+4QDU5DE2nQ9nDuVTqobD4b8mGGyPMbIZnqyMsEcaGQy67XIw/Jw==",
            "CatalogDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9: Default discriminator property changed from "Discriminator" to "$type".
        // Existing documents already store "Discriminator", so we must explicitly preserve it.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator");

        modelBuilder.Entity<Product>()
            .ToContainer("Products")
            .HasPartitionKey(p => p.Category);
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
    public string Category { get; set; } = null!;
    public decimal Price { get; set; }
}

using Microsoft.EntityFrameworkCore;

class ProductService
{
    // EF Core 9: The Cosmos DB provider no longer supports synchronous I/O.
    // Calls like .ToList(), .First(), .SaveChanges() throw InvalidOperationException.
    // All Cosmos queries and saves must use async methods.

    // ──── BEFORE (EF Core 8 – synchronous, now broken) ────
    // List<Product> GetAllProducts(CosmosDbContext db)
    // {
    //     return db.Products.ToList();
    // }
    //
    // Product? FindCheapest(CosmosDbContext db)
    // {
    //     return db.Products.OrderBy(p => p.Price).FirstOrDefault();
    // }
    //
    // void CreateProduct(CosmosDbContext db, Product product)
    // {
    //     db.Products.Add(product);
    //     db.SaveChanges();
    // }

    // ──── AFTER (EF Core 9 – async) ────
    async Task<List<Product>> GetAllProductsAsync(CosmosDbContext db)
    {
        return await db.Products.ToListAsync();
    }

    async Task<Product?> FindCheapestAsync(CosmosDbContext db)
    {
        return await db.Products.OrderBy(p => p.Price).FirstOrDefaultAsync();
    }

    async Task CreateProductAsync(CosmosDbContext db, Product product)
    {
        db.Products.Add(product);
        await db.SaveChangesAsync();
    }
}

